    High = 3,
    VeryHigh = 4,
    Ultra = 5,
}


function LxGameMgr:Initialize()
    LxBaseMgr.Initialize(self)

    self._shouldFrameRate = 60
    self._isFrameRateMax = false
    self._notchInfo = {0,0,0,0}

    self._multiplyScale = 1
    self._shouldTimeScale = 1
    self._timePause = false

    self._realTimeScale = 0
    self._realFrameRate = 0

    self._designWidth = 0
    self._designHeight = 0

    self._notchEnabled = false --仅表示竖屏上下需要适配
    self._safeArea = {x = 0, y=0, width = 0, height = 0}
    self._notchMin = {x = 0, y = 0}
    self._notchMax = {x = 1, y = 1}

    self._timeScheduleMap = {}

    ---@type LxBaseMgr[]
    self._updateMgrList = nil --需要循环检测的管理器
end

function LxGameMgr:Dispose()
    self:StopPauseTimer()

    if self._timeScheduleMap then
        for k,v in ipairs(self._timeScheduleMap) do
            self._timeScheduleMap[k] = nil
        end
    end
    LxBaseMgr.Dispose(self)
end

