function LxGameMgr:OnUpdate()
    for k,v in ipairs(self._updateMgrList) do
        v:OnUpdate()
    end

    for k,v in pairs(self._timeScheduleMap) do
        k:OnUpdate()
    end

    self:MonitorScreenResize()
end

function LxGameMgr:RegisterTimeSchedule(tblInst)
    if self._timeScheduleMap then
        self._timeScheduleMap[tblInst] = true
    end
end

function LxGameMgr:UnRegisterTimeSchedule(tblInst)
    if self._timeScheduleMap then
        self._timeScheduleMap[tblInst] = nil
    end
end

