function LxGameMgr:MonitorScreenResize()
    if self._lastWidth ~= Screen.width or self._lastHeight ~= Screen.height then
        if LOG_INFO_ENABLED then
            printError("GameMgr", "screen resize ... from %s,%s to %s,%s", tostring(self._lastWidth), tostring(self._lastHeight), tostring(Screen.width), tostring(Screen.height))
        end
        self._lastHeight = Screen.height
        self._lastWidth = Screen.width
        --self:InitNotch()
        --FireEvent(EventNames.APPLICATION_SCREEN_SIZE_CHANGE)
        self:OnAppScreenResize()
    end
end

