function LxGameMgr:SetGameTimeScale(scale)
    self._backGametimeScale = scale
end

function LxGameMgr:SetGameTimeScaleApply(scale)
    self:SetGameTimeScale(scale)
    self:ApplyGameTimeScale()
end

function LxGameMgr:ApplyGameTimeScale()
    if self._backTimePause then return end

    local applyScale = 1
    if self._backGametimeScale then
        applyScale = self._backGametimeScale
    end

    if self._baseTimeScale then
        applyScale = applyScale * self._baseTimeScale
    end

    if LOG_INFO_ENABLED then
        print("LGame:ApplyGameTimeScale()   "..applyScale)
    end

    Time.timeScale = applyScale
end

function LxGameMgr:DoPauseGameTime()
    self._backTimePause = true
    Time.timeScale = 0
end

function LxGameMgr:DoResumeGameTime()
    self._backTimePause = false
    self:ApplyGameTimeScale()
end

function LxGameMgr:SetBaseTimeScale(baseTimeScale)
    if self._baseTimeScale == baseTimeScale then return end

    self._baseTimeScale = baseTimeScale
    self:ApplyGameTimeScale()
end

function LxGameMgr:GetBackTimeScale()
    return self._backGametimeScale or 1
end


function LxGameMgr:OnApplicationQuit()
    if LOG_INFO_ENABLED then
        printInfo("GameMgr", "--->>>OnApplicationQuit ... ")
    end
end

function LxGameMgr:OnAppLowMemory()
    if LOG_INFO_ENABLED then
        printInfo("GameMgr", "--->>>OnAppLowMemory ... ")
    end
    if (gLGameMemory) then
        gLGameMemory:OnLowMemory("app_low_memory")
    end
end

function LxGameMgr:OnApplicationFocus(focus)
    if LOG_INFO_ENABLED then
        printInfo("GameMgr", "--->>>OnApplicationFocus ... focus:"..tostring(focus))
    end
end

function LxGameMgr:StopPauseTimer()
    if self._pauseTimer then
        LxTimer.DelayTimeStop(self._pauseTimer)
        self._pauseTimer = nil
    end
end

function LxGameMgr:StartPauseTimer(last)
    self:StopPauseTimer()
    self._pauseTimer = LxTimer.DelayFrameCall(function ()
        if last and last > 0 then
            local distime = Time.RawUnityEngineTime.realtimeSinceStartup - last
            if distime > 3600 then
                MgrCenter.NetworkMgr:StopConnect("long time not active")
                RestartGame()
            else
                FireEvent(EventNames.APPLICATION_RESUME,distime)
            end
        end
    end)
end

function LxGameMgr:OnApplicationPause(pause)
    if LOG_INFO_ENABLED then
        printInfo("GameMgr", "--->>>OnApplicationPause ... pause:"..tostring(pause))
    end
    --if pause then
    --    self._pauseStartTime = PJXUtil.GetRealtimeSinceStartup()
    --    FireEvent(EventNames.GAME_PAUSE_CHANGE, pause, 0)
    --else
    --    local startTime = self._pauseStartTime or PJXUtil.GetRealtimeSinceStartup()
    --    self._pauseStartTime = nil
    --    local holdTime = PJXUtil.GetRealtimeSinceStartup() - startTime
    --    FireEvent(EventNames.GAME_PAUSE_CHANGE, pause, holdTime)
    --end

    if pause then
        self:StopPauseTimer()
        self._lastPauseTime = Time.RawUnityEngineTime.realtimeSinceStartup
    else
        local last = self._lastPauseTime
        self._lastPauseTime = nil
        self:StartPauseTimer(last)
    end
    if gLGameQuality then
        gLGameQuality:OnApplicationPause(pause)
    end
    if MgrCenter.NetworkMgr then
        MgrCenter.NetworkMgr:OnApplicationPause(pause)
    end
    if gLGameLogin then
        gLGameLogin:OnApplicationPause(pause)
    end
    if gLGameUI then
        gLGameUI:OnApplicationPause(pause)
    end

    --TODO 回到前台释放资源检测
    LxResUtil.RunUnusedAssetUnload()

    if gLFightManager then
        gLFightManager:OnApplicationPause(pause)
    end

    if gLGameScene then
        gLGameScene:OnApplicationPause(pause)
    end

    if pause and GF and GF.IsInMainScene() then
        LxAlarmHelper.SetOfflineAlarm()
    end

    FireEvent(EventNames.APPLICATION_PAUSE, pause)

    if gLSdkImpl then gLSdkImpl:CallMethod(LSdkMethod.OnApplicationPause, pause) end
        
end

function LxGameMgr:OnAppScreenResize()
    if gLGameScene then
        gLGameScene:OnAppScreenResize()
    end
    LNotchUtil.OnAppScreenResize()
    FireEvent(EventNames.GAME_SCREEN_RESETSIZE)
end

function LxGameMgr:OnBackPressed()
    if gLGameDebug then
        gLGameDebug:OnBackPressed()
    end

    if gLGameUI then
        gLGameUI:OnBackPressed()
    end
end

